/// <summary>
/// Class entry point. The system will call this method when a designated menu 
/// is selected or when execution starts and this class is set as the startup class.
/// </summary>
/// <param name = "_args">The specified arguments.</param>
public static void main(Args _args)
{
    VendInvoiceJour vendInvoiceJour;
    GeneralJournalEntry generalJournalEntry;
    GeneralJournalAccountEntry generalJournalAccountEntry;

    ttsbegin;


    while select forupdate vendInvoiceJour
        where vendInvoiceJour.DataAreaId == "O051"
    {
        while select firstOnly generalJournalEntry
            where generalJournalEntry.SubledgerVoucher == vendInvoiceJour.LedgerVoucher
        {
            while select forupdate generalJournalAccountEntry
                where generalJournalAccountEntry.GeneralJournalEntry == generalJournalEntry.RecId
            {
                generalJournalAccountEntry.Text = vendInvoiceJour.Description;
                generalJournalAccountEntry.update();
            }
        }
    }

    ttscommit;

    info("Update is completed successfully.");
}
